          "tag": "promote_to_vendor_ns",
          "source": "def nsObj = ctx['a2i']; if (nsObj == null || nsObj.isEmpty()) return; if (ctx.aws == null) ctx.aws = new HashMap(); def svc = ctx.aws.containsKey('a2i') ? ctx.aws.get('a2i') : new HashMap(); for (def entry : nsObj.entrySet()) {   if (entry.getKey().equals('parsed')) continue;   if (!svc.containsKey(entry.getKey())) {     svc.put(entry.getKey(), entry.getValue());   } } ctx.aws.put('a2i', svc);",
