          "tag": "promote_to_vendor_ns",
          "source": "def nsObj = ctx['networkmanager']; if (nsObj == null || nsObj.isEmpty()) return; if (ctx.aws == null) ctx.aws = new HashMap(); def svc = ctx.aws.containsKey('networkmanager') ? ctx.aws.get('networkmanager') : new HashMap(); for (def entry : nsObj.entrySet()) {   if (entry.getKey().equals('parsed')) continue;   if (!svc.containsKey(entry.getKey())) {     svc.put(entry.getKey(), entry.getValue());   } } ctx.aws.put('networkmanager', svc);",
